import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar.jsx';
import LoginPage from './pages/LoginPage.jsx';
import MoviesPage from './pages/MoviesPage.jsx';
import MovieDetailPage from './pages/MovieDetailPage.jsx';
import ProfilePage from './pages/ProfilePage.jsx';
import { auth } from './auth.js';

function ProtectedRoute({ children }) {
  return auth.isLoggedIn() ? children : <Navigate to="/login" />;
}

function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <div className="container py-4">
        <Routes>
          <Route path="/" element={<Navigate to="/movies" />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/movies" element={<MoviesPage />} />
          <Route path="/movies/:id" element={<MovieDetailPage />} />
          <Route
            path="/profile"
            element={
              <ProtectedRoute>
                <ProfilePage />
              </ProtectedRoute>
            }
          />
        </Routes>
      </div>
    </BrowserRouter>
  );
}

export default App;

const API = '';

async function request(path, options = {}) {
  const res = await fetch(`${API}${path}`, {
    headers: { 'Content-Type': 'application/json' },
    ...options
  });

  if (!res.ok) {
    const text = await res.text();
    let message = `HTTP ${res.status}`;
    try {
      const parsed = text ? JSON.parse(text) : null;
      message = parsed?.error || parsed?.message || message;
    } catch {
      if (text) message = text;
    }
    throw new Error(message);
  }

  if (res.status === 204) return null;
  const bodyText = await res.text();
  if (!bodyText) return null;
  return JSON.parse(bodyText);
}

export const api = {
  login: (username, parola) =>
    request('/api/auth/login', {
      method: 'POST',
      body: JSON.stringify({ username, parola })
    }),
  getFilme: () => request('/api/filme'),
  getFilmeByCategorie: (idCategorie) => request(`/api/filme/categorie/${idCategorie}`),
  getFilm: (id) => request(`/api/filme/${id}`),
  getCategorii: () => request('/api/categorii'),
  getRecenziiFilm: (idFilm) => request(`/api/recenzii/film/${idFilm}`),
  postRecenzie: (data) =>
    request('/api/recenzii', { method: 'POST', body: JSON.stringify(data) }),
  getEtichete: () => request('/api/etichete'),
  addEticheta: (idRecenzie, idEticheta) =>
    request(`/api/recenzii-etichete/${idRecenzie}/${idEticheta}`, { method: 'POST' }),
  postVizualizare: (data) =>
    request('/api/vizualizari', { method: 'POST', body: JSON.stringify(data) }),
  getIstoric: (idClient) => request(`/api/vizualizari/client/${idClient}`),
  getRecomandari: (idClient) => request(`/api/stats/recomandari/${idClient}`),
  getProfil: (idClient) => request(`/api/stats/profil/${idClient}`),
  getSimilari: (idClient, topN = 5) =>
    request(`/api/stats/similari/${idClient}?topN=${topN}`),
  getActoriFilm: (idFilm) => request(`/api/actori/film/${idFilm}`)
};

const KEY = 'movieapp_user';

export const auth = {
  save: (user) => localStorage.setItem(KEY, JSON.stringify(user)),
  get: () => {
    const data = localStorage.getItem(KEY);
    return data ? JSON.parse(data) : null;
  },
  clear: () => localStorage.removeItem(KEY),
  isLoggedIn: () => localStorage.getItem(KEY) !== null
};

function MovieCard({ movie, onClick }) {
  return (
    <div className="card h-100" style={{ cursor: 'pointer' }} onClick={onClick}>
      <div className="card-body">
        <h5 className="card-title">{movie.titlu}</h5>
        <p className="card-text small text-muted">
          {movie.descriere ? `${movie.descriere.substring(0, 100)}...` : 'Fara descriere'}
        </p>
        <div className="d-flex justify-content-between">
          <small>⭐ {movie.rating?.toFixed?.(1) || movie.rating || 'N/A'}</small>
          <small>{movie.dataLansare || movie.data_lansare || ''}</small>
        </div>
      </div>
    </div>
  );
}

export default MovieCard;

import { Link, useNavigate } from 'react-router-dom';
import { auth } from '../auth.js';

function Navbar() {
  const navigate = useNavigate();
  const user = auth.get();

  const handleLogout = () => {
    auth.clear();
    navigate('/login');
  };

  return (
    <nav className="navbar navbar-expand-lg navbar-dark bg-dark">
      <div className="container">
        <Link className="navbar-brand" to="/movies">
           MovieApp
        </Link>
        <div className="collapse navbar-collapse show">
          <ul className="navbar-nav me-auto mb-2 mb-lg-0">
            <li className="nav-item">
              <Link className="nav-link" to="/movies">
                Filme
              </Link>
            </li>
            {user && (
              <li className="nav-item">
                <Link className="nav-link" to="/profile">
                  Profil
                </Link>
              </li>
            )}
          </ul>
          <div className="d-flex align-items-center gap-2">
            {user ? (
              <>
                <span className="text-light small">Salut, {user.nume}!</span>
                <button className="btn btn-outline-light btn-sm" onClick={handleLogout}>
                  Logout
                </button>
              </>
            ) : (
              <Link className="btn btn-outline-light btn-sm" to="/login">
                Login
              </Link>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;

import { useEffect, useMemo, useState } from 'react';
import { api } from '../api.js';

function groupBySentiment(etichete) {
  return etichete.reduce(
    (acc, e) => {
      const key = e.sentiment || 'NEUTRU';
      acc[key] = acc[key] || [];
      acc[key].push(e);
      return acc;
    },
    { POZITIV: [], NEGATIV: [], NEUTRU: [] }
  );
}

function ReviewForm({ idFilm, idClient, onSubmitted }) {
  const [nota, setNota] = useState(8);
  const [textComentariu, setTextComentariu] = useState('');
  const [etichete, setEtichete] = useState([]);
  const [selected, setSelected] = useState(new Set());
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    let ignore = false;
    api
      .getEtichete()
      .then((data) => {
        if (!ignore) setEtichete(data || []);
      })
      .catch((err) => {
        if (!ignore) setError(err.message);
      });
    return () => {
      ignore = true;
    };
  }, []);

  const grouped = useMemo(() => groupBySentiment(etichete), [etichete]);

  const toggle = (id) => {
    const copy = new Set(selected);
    if (copy.has(id)) copy.delete(id);
    else copy.add(id);
    setSelected(copy);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const recenzie = await api.postRecenzie({
        idClient,
        idFilm,
        nota: Number(nota),
        textComentariu
      });

      const idRecenzie = recenzie?.id || recenzie?.idRecenzie;
      for (const idEticheta of selected) {
        await api.addEticheta(idRecenzie, idEticheta);
      }
      setTextComentariu('');
      setSelected(new Set());
      if (onSubmitted) onSubmitted();
    } catch (err) {
      const message = err.message || 'Eroare la trimiterea recenziei.';
      if (message.includes('409') || message.toLowerCase().includes('deja')) {
        setError('Ai recenzat deja acest film.');
      } else {
        setError(message);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="card card-body">
      <h5 className="mb-3">Adauga o recenzie</h5>
      {error && <div className="alert alert-danger">{error}</div>}
      <div className="mb-3">
        <label className="form-label">Nota (1-10)</label>
        <input
          type="number"
          min="1"
          max="10"
          className="form-control"
          value={nota}
          onChange={(e) => setNota(e.target.value)}
        />
      </div>
      <div className="mb-3">
        <label className="form-label">Comentariu</label>
        <textarea
          className="form-control"
          rows="3"
          value={textComentariu}
          onChange={(e) => setTextComentariu(e.target.value)}
        />
      </div>

      <div className="mb-3">
        <label className="form-label">Etichete</label>
        <div className="row">
          {['POZITIV', 'NEGATIV', 'NEUTRU'].map((sentiment) => (
            <div className="col-md-4" key={sentiment}>
              <div className="small text-muted mb-1">{sentiment}</div>
              {grouped[sentiment].length === 0 && (
                <div className="text-muted small">-</div>
              )}
              {grouped[sentiment].map((e) => (
                <div className="form-check" key={e.id}>
                  <input
                    className="form-check-input"
                    type="checkbox"
                    id={`tag-${e.id}`}
                    checked={selected.has(e.id)}
                    onChange={() => toggle(e.id)}
                  />
                  <label className="form-check-label" htmlFor={`tag-${e.id}`}>
                    {e.denumire}
                  </label>
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>

      <button className="btn btn-primary" type="submit" disabled={loading}>
        {loading ? 'Se posteaza...' : 'Posteaza'}
      </button>
    </form>
  );
}

export default ReviewForm;

function ReviewList({ reviews }) {
  if (!reviews || reviews.length === 0) {
    return <div className="text-muted">Nu exista recenzii inca.</div>;
  }

  return (
    <div className="list-group">
      {reviews.map((r) => (
        <div key={r.id || `${r.idClient}-${r.idFilm}`} className="list-group-item">
          <div className="d-flex justify-content-between align-items-center">
            <strong>{r.numeClient || r.clientNume || r.username || 'Client'}</strong>
            <span className="badge bg-primary">{r.nota}</span>
          </div>
          {r.textComentariu && <p className="mb-1">{r.textComentariu}</p>}
          {r.dataPostare && <small className="text-muted">{r.dataPostare}</small>}
        </div>
      ))}
    </div>
  );
}

export default ReviewList;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.jsx';
import './styles.css';

ReactDOM.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../api.js';
import { auth } from '../auth.js';

function LoginPage() {
  const [username, setUsername] = useState('');
  const [parola, setParola] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const user = await api.login(username, parola);
      auth.save(user);
      navigate('/movies');
    } catch (err) {
      setError(err.message || 'Autentificare esuata.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="row justify-content-center">
      <div className="col-md-6 col-lg-5">
        <div className="card card-body shadow-sm">
          <h4 className="mb-3">Autentificare</h4>
          {error && <div className="alert alert-danger">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label className="form-label">Username</label>
              <input
                className="form-control"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
              />
            </div>
            <div className="mb-3">
              <label className="form-label">Parola</label>
              <input
                type="password"
                className="form-control"
                value={parola}
                onChange={(e) => setParola(e.target.value)}
              />
            </div>
            <button className="btn btn-primary w-100" disabled={loading}>
              {loading ? 'Se autentifica...' : 'Login'}
            </button>
          </form>
          <div className="text-muted small mt-3">Test: client1 / parola1</div>
        </div>
      </div>
    </div>
  );
}

export default LoginPage;

import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { api } from '../api.js';
import { auth } from '../auth.js';
import ReviewList from '../components/ReviewList.jsx';
import ReviewForm from '../components/ReviewForm.jsx';

function MovieDetailPage() {
  const { id } = useParams();
  const user = auth.get();
  const [movie, setMovie] = useState(null);
  const [actors, setActors] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [actionMessage, setActionMessage] = useState('');

  const loadAll = async () => {
    setLoading(true);
    setError('');
    try {
      const [movieData, actorData, reviewData] = await Promise.all([
        api.getFilm(id),
        api.getActoriFilm(id),
        api.getRecenziiFilm(id)
      ]);
      setMovie(movieData);
      setActors(actorData || []);
      setReviews(reviewData || []);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAll();
  }, [id]);

  const handleVizionare = async () => {
    if (!user) return;
    setActionMessage('');
    try {
      await api.postVizualizare({
        idClient: user.id,
        idVersiune: 1,
        durata: 90,
        stare: 'COMPLETED'
      });
      setActionMessage('Vizionare inregistrata!');
    } catch (err) {
      setActionMessage(err.message || 'Eroare la inregistrare.');
    }
  };

  if (loading) return <div>Se incarca...</div>;
  if (error) return <div className="alert alert-danger">{error}</div>;
  if (!movie) return <div className="text-muted">Film inexistent.</div>;

  return (
    <div className="row g-4">
      <div className="col-lg-8">
        <div className="card card-body mb-3">
          <h3 className="mb-2">{movie.titlu}</h3>
          <p className="text-muted">{movie.descriere || 'Fara descriere'}</p>
          <div className="d-flex gap-3 flex-wrap">
            <span>⭐ {movie.rating?.toFixed?.(1) || movie.rating || 'N/A'}</span>
            <span>Data lansare: {movie.dataLansare || movie.data_lansare || '-'}</span>
            <span>Categorie: {movie.idCategorie || movie.id_categorie || '-'}</span>
          </div>
          {user && (
            <button className="btn btn-success mt-3" onClick={handleVizionare}>
              Vizioneaza
            </button>
          )}
          {actionMessage && <div className="alert alert-info mt-3">{actionMessage}</div>}
        </div>

        <div className="card card-body mb-3">
          <h5>Actori</h5>
          {actors.length === 0 ? (
            <div className="text-muted">Nu exista actori pentru acest film.</div>
          ) : (
            <ul className="list-group list-group-flush">
              {actors.map((a) => (
                <li key={a.idActor || a.id_actor} className="list-group-item">
                  {(a.numeScena || a.nume_scena || '').trim() && (
                    <strong>{a.numeScena || a.nume_scena}</strong>
                  )}{' '}
                  {a.nume} {a.prenume} — <span className="text-muted">{a.rol}</span>
                </li>
              ))}
            </ul>
          )}
        </div>

        <div className="card card-body mb-3">
          <h5>Recenzii</h5>
          <ReviewList reviews={reviews} />
        </div>

        {user && (
          <ReviewForm
            idFilm={movie.id}
            idClient={user.id}
            onSubmitted={loadAll}
          />
        )}
      </div>

      <div className="col-lg-4">
        <div className="card card-body">
          <h6>Detalii rapide</h6>
          <div className="small text-muted">
            Autentificarea foloseste localStorage. Vizionarea este simulata.
          </div>
        </div>
      </div>
    </div>
  );
}

export default MovieDetailPage;

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../api.js';
import MovieCard from '../components/MovieCard.jsx';

function MoviesPage() {
  const [filme, setFilme] = useState([]);
  const [categorii, setCategorii] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const loadData = async (category) => {
    setLoading(true);
    setError('');
    try {
      const [cats, movies] = await Promise.all([
        api.getCategorii(),
        category === 'all' ? api.getFilme() : api.getFilmeByCategorie(category)
      ]);
      setCategorii(cats || []);
      setFilme(movies || []);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData(selectedCategory);
  }, [selectedCategory]);

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h3 className="mb-0">Filme</h3>
        <select
          className="form-select w-auto"
          value={selectedCategory}
          onChange={(e) => setSelectedCategory(e.target.value)}
        >
          <option value="all">Toate categoriile</option>
          {categorii.map((c) => (
            <option key={c.id} value={c.id}>
              {c.nume}
            </option>
          ))}
        </select>
      </div>

      {loading && <div>Se incarca...</div>}
      {error && <div className="alert alert-danger">{error}</div>}

      {!loading && !error && filme.length === 0 && (
        <div className="text-muted">Nu exista filme.</div>
      )}

      <div className="row g-3">
        {filme.map((movie) => (
          <div key={movie.id} className="col-md-4">
            <MovieCard movie={movie} onClick={() => navigate(`/movies/${movie.id}`)} />
          </div>
        ))}
      </div>
    </div>
  );
}

export default MoviesPage;

import { useEffect, useState } from 'react';
import { api } from '../api.js';
import { auth } from '../auth.js';
import MovieCard from '../components/MovieCard.jsx';

function ProfilePage() {
  const user = auth.get();
  const [profil, setProfil] = useState(null);
  const [recomandari, setRecomandari] = useState([]);
  const [istoric, setIstoric] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    let ignore = false;
    const load = async () => {
      setLoading(true);
      setError('');
      try {
        const [profilData, recData, istoricData] = await Promise.all([
          api.getProfil(user.id),
          api.getRecomandari(user.id),
          api.getIstoric(user.id)
        ]);
        if (!ignore) {
          setProfil(profilData);
          setRecomandari(recData || []);
          setIstoric(istoricData || []);
        }
      } catch (err) {
        if (!ignore) setError(err.message);
      } finally {
        if (!ignore) setLoading(false);
      }
    };

    load();
    return () => {
      ignore = true;
    };
  }, [user.id]);

  if (loading) return <div>Se incarca...</div>;
  if (error) return <div className="alert alert-danger">{error}</div>;

  return (
    <div className="row g-4">
      <div className="col-12">
        <h3>Profil client</h3>
      </div>

      <div className="col-md-4">
        <div className="card card-body">
          <h5>Profil cinematografic</h5>
          <div className="text-muted small mb-2">
            Date generate de procedura p_profil_cinematografic
          </div>
          {profil ? (
            <ul className="list-group list-group-flush">
              <li className="list-group-item">Categorie preferata: {profil.categoriePreferata || profil.categorie_preferata || '-'}</li>
              <li className="list-group-item">Actor preferat: {profil.actorPreferat || profil.actor_preferat || '-'}</li>
              <li className="list-group-item">Rating mediu: {profil.ratingMediu || profil.rating_mediu || '-'}</li>
              <li className="list-group-item">Total filme vazute: {profil.totalFilmeVazute || profil.total_filme_vazute || '-'}</li>
              <li className="list-group-item">Total recenzii: {profil.totalRecenzii || profil.total_recenzii || '-'}</li>
              <li className="list-group-item">Sentiment dominant: {profil.sentimentDominant || profil.sentiment_dominant || '-'}</li>
            </ul>
          ) : (
            <div className="text-muted">Nu exista date.</div>
          )}
        </div>
      </div>

      <div className="col-md-8">
        <div className="card card-body mb-4">
          <h5>Recomandari pentru tine</h5>
          <div className="text-muted small mb-2">
            Recomandari generate de procedura p_recomandari_pentru_client
          </div>
          {recomandari.length === 0 ? (
            <div className="text-muted">Nu exista recomandari.</div>
          ) : (
            <div className="row g-3">
              {recomandari.slice(0, 10).map((movie) => (
                <div key={movie.id || movie.id_film} className="col-md-6">
                  <MovieCard movie={movie} onClick={() => {}} />
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="card card-body">
          <h5>Istoric vizionari</h5>
          {istoric.length === 0 ? (
            <div className="text-muted">Nu exista vizionari.</div>
          ) : (
            <div className="table-responsive">
              <table className="table table-sm">
                <thead>
                  <tr>
                    <th>Titlu</th>
                    <th>Versiune</th>
                    <th>Data</th>
                    <th>Durata</th>
                    <th>Stare</th>
                  </tr>
                </thead>
                <tbody>
                  {istoric.map((v, idx) => (
                    <tr key={v.id || idx}>
                      <td>{v.titlu || v.titluFilm || v.titlu_film || '-'}</td>
                      <td>{v.versiune || v.idVersiune || v.id_versiune || '-'}</td>
                      <td>{v.dataVizualizare || v.data_vizualizare || '-'}</td>
                      <td>{v.durata || '-'}</td>
                      <td>{v.stare || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default ProfilePage;

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  server: {
    proxy: {
      '/api': 'http://localhost:8080'
    }
  }
});
